"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";

const questions = [
    {
        id: 1,
        question: "How familiar are you with Data Structures & Algorithms (DSA)?",
        options: [
            "Beginner — I’m just starting out",
            "Intermediate — I know the basics but struggle in problems",
            "Advanced — I can solve most problems confidently",
        ],
    },
    {
        id: 2,
        question: "Which device do you use most?",
        options: ["Mobile", "Laptop", "Tablet", "Desktop"],
    },
    {
        id: 3,
        question: "How often do you use AI tools?",
        options: ["Daily", "Weekly", "Monthly", "Rarely"],
    },
    {
        id: 4,
        question: "What is your experience level?",
        options: ["Beginner", "Intermediate", "Advanced", "Expert"],
    },
    {
        id: 5,
        question: "Would you recommend our platform?",
        options: ["Yes", "Maybe", "Not Sure", "No"],
    },
];

const avatars = [
    "https://img.freepik.com/free-photo/pretty-smiling-joyfully-female-with-fair-hair-dressed-casually-looking-with-satisfaction_176420-15187.jpg",
    "https://img.freepik.com/free-photo/handsome-young-cheerful-man-with-arms-crossed_171337-1073.jpg?semt=ais_user_personalization&w=740&q=80",
    "https://static.vecteezy.com/system/resources/thumbnails/005/346/410/small/close-up-portrait-of-smiling-handsome-young-caucasian-man-face-looking-at-camera-on-isolated-light-gray-studio-background-photo.jpg",
];

export default function FormPage() {
    const router = useRouter();

    const [step, setStep] = useState(0);
    const [selectedAvatar, setSelectedAvatar] = useState<string | null>(null);
    const [name, setName] = useState("");
    const [answers, setAnswers] = useState<{ [key: number]: string }>({});
    const [loading, setLoading] = useState(false);

    const totalSteps = questions.length + 2; // avatar + name + questions
    const progress = Math.round((step / totalSteps) * 100);

    const currentQuestion = questions[step - 2];

    const handleSelect = (option: string) => {
        setAnswers((prev) => ({
            ...prev,
            [currentQuestion.id]: option,
        }));
    };

    const handleNext = () => {
        // Step 0 → Avatar
        if (step === 0) {
            if (!selectedAvatar) {
                alert("Please select an avatar.");
                return;
            }
            setStep(1);
            return;
        }

        // Step 1 → Name
        if (step === 1) {
            if (!name.trim()) {
                alert("Please enter your name.");
                return;
            }
            setStep(2);
            return;
        }

        // Questions
        if (!answers[currentQuestion.id]) {
            alert("Please select an option.");
            return;
        }

        setStep((prev) => prev + 1);
    };

    const handleSubmit = async () => {
        try {
            setLoading(true);

            await fetch("/api/survey", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    name,
                    avatar: selectedAvatar,
                    answers,
                }),
            });

            router.push("/thank-you");
        } catch (error) {
            console.error("Submission error:", error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <section className="min-h-screen bg-gradient-to-br from-[#0f172a] via-[#111827] to-[#1e293b] flex items-center justify-center px-4 py-10">
            <div className="w-full max-w-4xl">

                {/* Progress */}
                <div className="mb-6">
                    <div className="flex justify-between items-center text-sm text-white/70 mb-2">
                        <span>
                            {step < 2
                                ? step === 0
                                    ? "Select Avatar"
                                    : "Enter Name"
                                : `Question ${step - 1} of ${questions.length}`}
                        </span>
                        <span className="text-[#FBBF24] font-semibold">
                            {progress}% Complete
                        </span>
                    </div>

                    <div className="w-full bg-white/10 h-2 rounded-full overflow-hidden">
                        <div
                            className="h-full bg-gradient-to-r from-purple-500 to-pink-500 transition-all duration-500"
                            style={{ width: `${progress}%` }}
                        />
                    </div>
                </div>

                {/* Card */}
                <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-10 shadow-2xl">

                    {/* ================= STEP 0 → AVATAR ================= */}
                    {step === 0 && (
                        <>
                            <h2 className="text-3xl md:text-4xl font-bold text-white mb-8">
                                Choose Your Avatar
                            </h2>



                            {/* Avatar Options */}
                            <div className="flex gap-10 justify-center">
                                {avatars.map((avatar, index) => (
                                    <button
                                        key={index}
                                        onClick={() => setSelectedAvatar(avatar)}
                                        className={`relative w-28 h-28 rounded-full transition-all duration-300
        ${selectedAvatar === avatar
                                                ? "ring-4 ring-purple-500 scale-110 shadow-[0_0_25px_rgba(168,85,247,0.6)]"
                                                : "hover:scale-105"
                                            }
      `}
                                    >
                                        <div className="relative w-full h-full rounded-full overflow-hidden">
                                            <Image
                                                src={avatar}
                                                alt="avatar"
                                                fill
                                                sizes="112px"
                                                className="object-cover"
                                            />
                                        </div>
                                    </button>
                                ))}
                            </div>
                            <div className="flex justify-end">
                                <button
                                    onClick={handleNext}
                                    className="px-8 py-3 rounded-xl bg-gradient-to-r from-purple-600 to-pink-500 text-white font-semibold"
                                >
                                    Next
                                </button>
                            </div>
                        </>
                    )}

                    {/* ================= STEP 1 → NAME ================= */}
                    {step === 1 && (
                        <>
                            <h2 className="text-3xl md:text-4xl font-bold text-white mb-8">
                                Enter Your Name
                            </h2>

                            <input
                                type="text"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="Your Name"
                                className="w-full px-6 py-4 rounded-xl bg-white/5 text-white border border-white/20 focus:outline-none focus:border-purple-500 transition"
                            />

                            <button
                                onClick={handleNext}
                                className="w-full mt-8 px-8 py-4 rounded-xl bg-gradient-to-r from-purple-600 to-pink-500 text-white font-semibold"
                            >
                                Next
                            </button>
                        </>
                    )}

                    {/* ================= QUESTIONS ================= */}
                    {step >= 2 && step < totalSteps && (
                        <>
                            <h2 className="text-3xl md:text-4xl font-bold text-white mb-8">
                                {currentQuestion.question}
                            </h2>

                            <div className="space-y-4">
                                {currentQuestion.options.map((option, index) => {
                                    const isSelected =
                                        answers[currentQuestion.id] === option;

                                    return (
                                        <button
                                            key={index}
                                            onClick={() => handleSelect(option)}
                                            className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl border transition-all
                      ${isSelected
                                                    ? "border-purple-500 bg-purple-600/20"
                                                    : "border-white/20 bg-white/5 hover:bg-white/10"
                                                }`}
                                        >
                                            <div
                                                className={`w-5 h-5 rounded-full border-2 flex items-center justify-center
                        ${isSelected
                                                        ? "border-purple-500"
                                                        : "border-white/40"
                                                    }`}
                                            >
                                                {isSelected && (
                                                    <div className="w-2.5 h-2.5 bg-purple-500 rounded-full" />
                                                )}
                                            </div>

                                            <span className="text-white text-lg">
                                                {option}
                                            </span>
                                        </button>
                                    );
                                })}
                            </div>

                            <div className="flex justify-between mt-10">
                                <button
                                    onClick={() => setStep((prev) => prev - 1)}
                                    className="px-6 py-3 rounded-xl bg-white/10 text-white"
                                >
                                    Previous
                                </button>

                                {step === totalSteps - 1 ? (
                                    <button
                                        onClick={handleSubmit}
                                        disabled={loading}
                                        className="px-8 py-3 rounded-xl bg-gradient-to-r from-purple-600 to-pink-500 text-white font-semibold"
                                    >
                                        {loading ? "Submitting..." : "Submit"}
                                    </button>
                                ) : (
                                    <button
                                        onClick={handleNext}
                                        className="px-8 py-3 rounded-xl bg-gradient-to-r from-purple-600 to-pink-500 text-white font-semibold"
                                    >
                                        Next
                                    </button>
                                )}
                            </div>
                        </>
                    )}

                </div>
            </div>
        </section>
    );
}
